changeSet.sql:
CREATE OR REPLACE FUNCTION sync_module_ifm_to_item_form_metadata() RETURNS TRIGGER AS $$ BEGIN IF pg_trigger_depth() > 1 THEN RETURN COALESCE(NEW, OLD); END IF;
IF (TG_OP = 'INSERT') THEN INSERT INTO item_form_metadata ( item_form_metadata_id, item_id, section_id, crf_version_id, ordinal, required, default_value, regexp, regexp_error_msg, response_layout, width_decimal, show_item, response_set_id ) VALUES ( NEW.item_form_metadata_id, NEW.item_id, NEW.section_id, NEW.crf_version_id, NEW.ordinal, NEW.required, NEW.default_value, NEW.regexp, NEW.regexp_error_msg, NEW.response_layout, NEW.width_decimal, NEW.show_item, NEW.response_set_id ) ON CONFLICT (item_form_metadata_id) DO UPDATE SET item_id = EXCLUDED.item_id, section_id = EXCLUDED.section_id, crf_version_id = EXCLUDED.crf_version_id, ordinal = EXCLUDED.ordinal, required = EXCLUDED.required, default_value = EXCLUDED.default_value, regexp = EXCLUDED.regexp, regexp_error_msg = EXCLUDED.regexp_error_msg, response_layout = EXCLUDED.response_layout, width_decimal = EXCLUDED.width_decimal, show_item = EXCLUDED.show_item, response_set_id = EXCLUDED.response_set_id; RETURN NEW; ELSIF (TG_OP = 'UPDATE') THEN UPDATE item_form_metadata SET item_id = NEW.item_id, section_id = NEW.section_id, crf_version_id = NEW.crf_version_id, ordinal = NEW.ordinal, required = NEW.required, default_value = NEW.default_value, regexp = NEW.regexp, regexp_error_msg = NEW.regexp_error_msg, response_layout = NEW.response_layout, width_decimal = NEW.width_decimal, show_item = NEW.show_item, response_set_id = NEW.response_set_id WHERE item_form_metadata_id = OLD.item_form_metadata_id; RETURN NEW; ELSIF (TG_OP = 'DELETE') THEN DELETE FROM item_form_metadata WHERE item_form_metadata_id = OLD.item_form_metadata_id; RETURN OLD; END IF; END; $$ LANGUAGE plpgsql;
CREATE OR REPLACE FUNCTION sync_item_form_metadata_to_module_ifm() RETURNS TRIGGER AS $$ BEGIN IF pg_trigger_depth() > 1 THEN RETURN COALESCE(NEW, OLD); END IF;
IF (TG_OP = 'INSERT') THEN INSERT INTO module_item_form_metadata ( item_form_metadata_id, item_id, section_id, crf_version_id, ordinal, required, default_value, regexp, regexp_error_msg, response_layout, width_decimal, show_item, response_set_id ) VALUES ( NEW.item_form_metadata_id, NEW.item_id, NEW.section_id, NEW.crf_version_id, NEW.ordinal, NEW.required, NEW.default_value, NEW.regexp, NEW.regexp_error_msg, NEW.response_layout, NEW.width_decimal, NEW.show_item, NEW.response_set_id ) ON CONFLICT (item_form_metadata_id) DO UPDATE SET item_id = EXCLUDED.item_id, section_id = EXCLUDED.section_id, crf_version_id = EXCLUDED.crf_version_id, ordinal = EXCLUDED.ordinal, required = EXCLUDED.required, default_value = EXCLUDED.default_value, regexp = EXCLUDED.regexp, regexp_error_msg = EXCLUDED.regexp_error_msg, response_layout = EXCLUDED.response_layout, width_decimal = EXCLUDED.width_decimal, show_item = EXCLUDED.show_item, response_set_id = EXCLUDED.response_set_id; RETURN NEW; ELSIF (TG_OP = 'UPDATE') THEN UPDATE module_item_form_metadata SET item_id = NEW.item_id, section_id = NEW.section_id, crf_version_id = NEW.crf_version_id, ordinal = NEW.ordinal, required = NEW.required, default_value = NEW.default_value, regexp = NEW.regexp, regexp_error_msg = NEW.regexp_error_msg, response_layout = NEW.response_layout, width_decimal = NEW.width_decimal, show_item = NEW.show_item, response_set_id = NEW.response_set_id WHERE item_form_metadata_id = OLD.item_form_metadata_id; RETURN NEW; ELSIF (TG_OP = 'DELETE') THEN DELETE FROM module_item_form_metadata WHERE item_form_metadata_id = OLD.item_form_metadata_id; RETURN OLD; END IF; END; $$ LANGUAGE plpgsql;

